<template>
  <v-container fluid class="pa-6 pt-4 fill-height cctv-manage">
    <v-row no-gutters class="fill-height">
      <v-sheet width="100%" height="33" class="d-flex align-center">
        <h3 class="font-weight-bold">{{ $t('cctvManage') }}</h3>
      </v-sheet>
      <v-sheet width="100%" height="calc(100% - 33px)" class="pt-0">
        <i-card-top
          :useBtnList="buttonUseList"
          @btnAdd="btnAdd()"
          @btnSearch="btnSearch()"
          @btnSave="btnSave()"
          @btnDelete="btnDelete()"
          class="d-flex mb-0"
        >
          <template #body>
            <v-sheet height="100%" class="d-flex align-center">
              <v-spacer />
            </v-sheet>
          </template>
        </i-card-top>
        <v-layout column>
          <DxDataGrid
            :key="gridKey"
            id="checkInfoDataGrid"
            class="cctv-api-server-manage-layout-col-height"
            :ref="dxDataGridRef"
            :data-source="cctvDataSource"
            :remote-operations="false"
            :show-borders="true"
            :show-row-lines="true"
            :column-auto-width="true"
            :allow-column-resizing="true"
            :allow-column-reordering="true"
            :repaint-changes-only="false"
            :focused-row-enabled="true"
            key-expr="cctv_id"
            @editing-start="onEditingStart"
            @editor-preparing="onEditorPreparing"
            @focused-row-changed="onFocusedRowChanged"
          >
            <DxEditing mode="batch" :allow-updating="true" :select-text-on-edit-start="true" />
            <DxScrolling row-rendering-mode="standard" />
            <DxSelection select-all-mode="allPages" show-check-boxes-mode="always" mode="multiple" />

            <DxColumn data-field="cctv_id" data-type="string" :caption="$t('cctvId')" alignment="center" :visible="true" :allow-editing="false" />
            <DxColumn data-field="cctv_name" data-type="string" css-class="devest-grid-header-require" :caption="$t('cctvNm')" alignment="center" :visible="true" :allow-editing="true" />
            <DxColumn data-field="camera_desc" data-type="string" :caption="$t('cameraDesc')" alignment="center" :visible="true" :allow-editing="true" />
            <DxColumn data-field="location" data-type="string" :caption="$t('cameraLocation')" alignment="center" :visible="true" :allow-editing="true" >
              <DxLookup :data-source="cctvLocationList" display-expr="location_name" value-expr="location_id" />
            </DxColumn>
            <DxColumn data-field="server_id" data-type="string" css-class="devest-grid-header-require" :caption="$t('serverId')" alignment="center" :visible="true" :allow-editing="true">
              <DxLookup :data-source="cctvApiServerDataSource" display-expr="server_name" value-expr="server_id" />
            </DxColumn>
            <!-- <DxColumn data-field="out_path" data-type="string" caption="out_path" alignment="center" :visible="true" :allow-editing="true" /> -->
            <DxColumn data-field="rtsp_add" data-type="string" css-class="devest-grid-header-require" :caption="$t('cctvAddr')" alignment="center" :visible="true" :allow-editing="true" />
            <DxColumn data-field="jit_only" data-type="boolean" :caption="$t('jitOnly')" alignment="center" :visible="true" :allow-editing="true" />
            <DxColumn data-field="remark" data-type="string" :caption="$t('remark')" alignment="center" :visible="true" :allow-editing="true" />
            <DxColumn data-field="created_at" data-type="string" :caption="$t('createdDate')" alignment="center" :visible="true" :allow-editing="false" />
            <DxColumn data-field="created_by" data-type="string" :caption="$t('writer')" alignment="center" :visible="true" :allow-editing="false" />
            <DxColumn data-field="updated_at" data-type="string" :caption="$t('updatedDate')" alignment="center" :visible="true" :allow-editing="false" />
            <DxColumn data-field="updated_by" data-type="string" :caption="$t('modifier')" alignment="center" :visible="true" :allow-editing="false" />
            <DxColumn
              data-field="pid"
              data-type="string"
              :caption="$t('runStatus')"
              alignment="center"
              :visible="true"
              :allow-editing="false"
              cell-template="runStatus"
            />
            <template #runStatus="{ data: cellInfo }">
              <template v-if="cellInfo.data.out_path">
                <template v-if="cellInfo.data.pid">
                  <!-- {{ $t('running') }} -->
                  <v-icon color="success">mdi-cctv</v-icon>
                </template>
                <template v-else>
                  <v-icon color="red">mdi-cctv</v-icon>
                </template>
              </template>
            </template>
            <DxColumn
              data-type="string"
              caption=""
              alignment="center"
              :visible="true"
              :allow-editing="false"
              header-cell-template="cctvProcessHeader"
              cell-template="cctvProcess"
            />
            <template #cctvProcessHeader="{ data: cellInfo }">
              <v-sheet color="white" class="d-flex align-center justify-start">
                <v-btn outlined text elevation="0" width="80" height="25" class="pa-1 pr-2 rounded-0" @click="onfullRun()">
                  <span class="primary--text text-caption">{{ $t('fullRun') }}</span>
                </v-btn>
                <v-btn outlined text elevation="0" width="80" height="25" class="pa-1 pr-2 rounded-0" @click="onfullEnd()">
                  <span class="error--text text-caption">{{ $t('fullEnd') }}</span>
                </v-btn>
              </v-sheet>
            </template>            
            <template #cctvProcess="{ data: cellInfo }">
              <template v-if="cellInfo.data.out_path">
                <v-sheet color="transparent" class="d-flex align-center justify-center">
                  <v-btn outlined text elevation="0" width="60" height="25" class="pa-1 pr-2 mr-2 rounded-0" @click="onRun(cellInfo.data.cctv_id, true)">
                    <span class="primary--text text-caption">{{ $t('run') }}</span>
                  </v-btn>
                  <v-btn outlined text elevation="0" width="60" height="25" class="pa-1 pr-2 mr-1 rounded-0" @click="onRun(cellInfo.data.cctv_id, false)">
                    <span class="error--text text-caption">{{ $t('end') }}</span>
                  </v-btn>
                </v-sheet>
              </template>
            </template>
          </DxDataGrid>
        </v-layout>
      </v-sheet>
    </v-row>
  </v-container>
</template>

<script>
import baseview from '@/views/base/baseview.vue'
import BaseDataGrid from '@/views/base/BaseDataGrid.vue'

import { getUserCd } from '@/utils/token'
import { getAiServerList } from '@/api/realTimeVideoSafetyManagement/safetyVideoServerManage.js'
import { getCCTVList, saveCCTV, deleteCCTV, runCCTVProcess, endCCTVProcess, stopCCTVProcessAll, runCCTVProcessAll
 } from '@/api/realTimeVideoSafetyManagement/safetyDetectionCameraManage.js'

export default {
  mixins: [baseview, BaseDataGrid],
  name: 'SafetyDetectionCameraManage',
  components: {
  },
  computed: {
    dataGridMain() {
      return this.$refs[this.dxDataGridRef].instance
    },
  },
  data() {
    return {
      gridKey: 0,
      newId: 0,
      dxDataGridRef: 'cctvManageDataGridRef',
      buttonUseList: [
        'btnSearch', //조회
        'btnAdd', //추가
        'btnSave', //저장
        'btnDelete' //삭제
      ],
      cctvDataSource: [],
      cctvLocationList: [ 
        { 
          'location_name': 'A동',
          'location_id': 'A동'
        },
        { 
          'location_name': 'B동',
          'location_id': 'B동'
        },
        { 
          'location_name': 'C동',
          'location_id': 'C동'
        },
        { 
          'location_name': 'D동',
          'location_id': 'D동'
        },
        { 
          'location_name': 'E동',
          'location_id': 'E동'
        },
        {
          'location_name': '3동',
          'location_id': '3동'
        },
      ],
      cctvApiServerDataSource: []
    }
  },
  methods: {
    getAiServer() {
      getAiServerList()
        .then(res => {
          this.cctvApiServerDataSource = res.list
        })
    },
    btnAdd() {
      this.newId++
      let newRow = {
        cctv_id : `NEW_CAM_${this.newId}`,
        cctv_name : '',
        camera_desc : '',
        location : '',
        server_id : '',
        rtsp_add : '',
        jit_only : false,
        remark : '',
        created_at : null,
        created_by : null,
        updated_at : null,
        updated_by : null,
        pid: '',
      }
      Object.defineProperty(newRow, '__created__', { value: true, writable: true, enumerable: true, configurable: true })
      this.GetDataGrid(this.dxDataGridRef).newRow(newRow)
      this.GetDataGrid(this.dxDataGridRef).selectRows(newRow.id, true)
    },
    btnSearch() {
      // checkCCTVProcessAll()
      //   .then(checkRes => {
          getCCTVList()
            .then(res => {
              this.newId = 0
              this.cctvDataSource = res.list
            })
        // })
        // .catch((e) => console.log(e))
    },
    async btnSave() {
      let selectedMainRows = await this.dataGridMain.getSelectedRowsData()
      if (!selectedMainRows.length) {
        this.vToastify(this.$t('selectionData'), 'warn')
        return
      }
      this.vToastifyPrompt(
        this.$t('doSaveData'),
        'info',
        current => {
          this.dataGridMain.saveEditData()
          if (selectedMainRows.every(el => {
            return el.cctv_name.trim() == ''
              || el.server_id.trim() == ''
              || el.rtsp_add.trim() == ''
          })) {
            this.vToastify(`${this.$t('msgReqValidate')},${this.$t('cctvNm')},${this.$t('serverId')},${this.$t('cctvAddr')}`, 'warn')
            return
          }
          this.openLoading('saving')
          this.dataGridMain.beginUpdate()
          const param = selectedMainRows.map(el => ({
            ...el,
            userCd: getUserCd()
          }))
          saveCCTV(param, true)
            .then(res => {
              this.btnSearch()
            })
            .catch(error => {
              console.error('CCTV Save Error', error)
            })
            .finally(() => {
              this.dataGridMain.clearSelection(); // ✅ 저장 후 선택 해제
              this.dataGridMain.endUpdate()
              this.endLoading()
            })
        },
        null,
        true
      ) 
    },
    async btnDelete() {
      let selectedMainRows = await this.dataGridMain.getSelectedRowsData()
      if (!selectedMainRows.length) {
        this.vToastify(this.$t('selectionData'), 'warn')
        return
      }
      this.vToastifyPrompt(
        this.$t('doDeleteData'),
        'info',
        current => {
          this.dataGridMain.beginUpdate()
          this.dataGridMain.saveEditData()
          this.openLoading('deleting')
          const param = selectedMainRows.filter(el => !el.__created__).map(el => el.cctv_id)
          const newIds = selectedMainRows.filter(el => el.__created__).map(el => el.cctv_id)
          this.cctvDataSource = this.cctvDataSource.filter(el => !newIds.includes(el.cctv_id))
          const finishEvent = () => {
            this.dataGridMain.endUpdate()
            this.FocusFirstRow(this.dataGridMain)
            this.endLoading()
          }
          if (param.length !== 0) {
            deleteCCTV(param, true)
              .then(res => {
                this.btnSearch()
              })
              .finally(() => {
                finishEvent()
              })
          } else {
            finishEvent()
          }
        },
        null,
        true
      )
    },
    onEditingStart(e) {

    },
    onFocusedRowChanged(e) {
      
    },
    onfullEnd() {
      stopCCTVProcessAll()
        .then(res => {
          this.btnSearch()
        })
    },
    onfullRun() {
      runCCTVProcessAll()
        .then(res => {
          this.btnSearch()
        })
    },
    onRun(param, isRun) {
      if(isRun) {
        runCCTVProcess(param)
        .then(res => {
          this.btnSearch()
        })
      } else {
        endCCTVProcess(param)
        .then(res => {
          this.btnSearch()
        })
      }
    }
  },
  mounted() {
    this.getAiServer()
    this.btnSearch()
  },
}
</script>

<style lang="scss">
.cctv-api-server-manage {
  $appBarHeight: 65px;
  $cardTitleHeight: 62px;
  $conditionOneHeight: 46px;
  $paddingHeight: 8px;
  $spare: 3.5vh;
  > div {
    position: relative;
  }
  &-layout-col-height {
    // max-width: 100% !important;
    min-height: calc(100vh - (#{$appBarHeight} + #{$cardTitleHeight} + #{$conditionOneHeight} + (#{$paddingHeight} * 5.8) + #{$spare})) !important;
  }
}
</style>
